fn support_string(value: Option<&Value>) -> Value {
    value
        .and_then(Value::as_str)
        .map(|text| Value::String(text.trim().chars().take(240).collect()))
        .unwrap_or(Value::Null)
}

fn support_artifact_forbidden_paths(value: &Value) -> Vec<String> {
    let mut paths = Vec::new();
    support_artifact_collect_forbidden_paths(value, "$", &mut paths);
    paths
}

fn support_artifact_collect_forbidden_paths(value: &Value, path: &str, paths: &mut Vec<String>) {
    match value {
        Value::Object(object) => {
            for (key, child) in object {
                let child_path = format!("{path}.{key}");
                let lower = key.to_ascii_lowercase();
                let redaction_manifest_path = path.starts_with("$.redaction");
                if !redaction_manifest_path
                    && matches!(
                        lower.as_str(),
                        "prompt"
                            | "selected_text"
                            | "message_body"
                            | "body"
                            | "record_payload"
                            | "payload_json"
                            | "raw"
                            | "token"
                            | "secret"
                    )
                {
                    paths.push(child_path.clone());
                }
                support_artifact_collect_forbidden_paths(child, child_path.as_str(), paths);
            }
        }
        Value::Array(items) => {
            for (index, child) in items.iter().enumerate() {
                support_artifact_collect_forbidden_paths(
                    child,
                    format!("{path}[{index}]").as_str(),
                    paths,
                );
            }
        }
        _ => {}
    }
}

fn policy_audit_actor_context(root: &Path, command: &BusinessCommand) -> Value {
    if let Ok(session) = rxdb_authenticated_session(root, command) {
        if let Some(user) = session.user {
            return serde_json::json!({
                "id": user.id,
                "display_name": user.display_name,
                "role": user.role,
                "trusted": true
            });
        }
    }
    let client_context = business_command_client_context_value(command);
    let actor = client_context
        .get("actor")
        .or_else(|| client_context.get("user"));
    let id = actor
        .and_then(|value| value.get("id"))
        .or_else(|| client_context.get("user_id"))
        .and_then(Value::as_str)
        .unwrap_or("rxdb-command");
    let display_name = actor
        .and_then(|value| value.get("display_name"))
        .or_else(|| actor.and_then(|value| value.get("name")))
        .or_else(|| client_context.get("display_name"))
        .and_then(Value::as_str)
        .unwrap_or(id);
    serde_json::json!({
        "id": id,
        "display_name": display_name,
        "trusted": false
    })
}

fn business_command_client_context_value(command: &BusinessCommand) -> Value {
    if let Value::String(ref raw) = command.client_context {
        serde_json::from_str(raw).unwrap_or_else(|_| command.client_context.clone())
    } else {
        command.client_context.clone()
    }
}

fn policy_audit_client_context(command: &BusinessCommand) -> Value {
    let client_context = business_command_client_context_value(command);
    let Some(object) = client_context.as_object() else {
        return Value::Null;
    };
    let mut audited = serde_json::Map::new();
    for key in [
        "source",
        "surface",
        "action",
        "mode",
        "target",
        "module",
        "module_id",
        "app_id",
        "source_module",
        "record_id",
        "record_type",
        "collection",
        "column",
        "active_scope",
        "version",
        "visibility",
    ] {
        if let Some(value) = object.get(key).and_then(policy_audit_safe_scalar) {
            audited.insert(key.to_string(), value);
        }
    }
    if let Some(scope) = object
        .get("visible_scope")
        .or_else(|| client_context.pointer("/scope/visible_scope"))
        .map(policy_audit_visible_scope_value)
    {
        audited.insert("visible_scope".to_string(), scope);
    }
    Value::Object(audited)
}

fn policy_audit_safe_scalar(value: &Value) -> Option<Value> {
    match value {
        Value::String(text) => Some(Value::String(policy_audit_truncate(text, 160))),
        Value::Number(_) | Value::Bool(_) | Value::Null => Some(value.clone()),
        Value::Array(_) | Value::Object(_) => None,
    }
}

fn policy_audit_visible_scope_value(value: &Value) -> Value {
    match value {
        Value::Object(object) => {
            let mut audited = serde_json::Map::new();
            for (key, nested) in object {
                if !policy_audit_visible_scope_key_allowed(key) {
                    continue;
                }
                let audited_value = policy_audit_visible_scope_value(nested);
                if !audited_value.is_null() {
                    audited.insert(key.clone(), audited_value);
                }
            }
            Value::Object(audited)
        }
        Value::Array(items) => Value::Array(
            items
                .iter()
                .take(24)
                .map(policy_audit_visible_scope_value)
                .filter(|item| !item.is_null())
                .collect(),
        ),
        Value::String(text) => Value::String(policy_audit_truncate(text, 240)),
        Value::Number(_) | Value::Bool(_) => value.clone(),
        Value::Null => Value::Null,
    }
}

fn policy_audit_visible_scope_key_allowed(key: &str) -> bool {
    matches!(
        key,
        "access"
            | "actor"
            | "app"
            | "app_id"
            | "badge"
            | "can_modify"
            | "can_read"
            | "can_write"
            | "collection"
            | "data"
            | "display_name"
            | "external_actions"
            | "id"
            | "key"
            | "label"
            | "lifecycle"
            | "mode"
            | "module_id"
            | "permission"
            | "permission_label"
            | "record_id"
            | "record_type"
            | "role"
            | "rows"
            | "scope"
            | "scope_id"
            | "scope_type"
            | "selection"
            | "source"
            | "status"
            | "target"
            | "title"
            | "trusted"
            | "value"
            | "version"
            | "visibility"
    )
}

fn policy_audit_truncate(text: &str, max_chars: usize) -> String {
    let mut truncated = String::new();
    for (index, ch) in text.chars().enumerate() {
        if index >= max_chars {
            truncated.push_str("...");
            return truncated;
        }
        truncated.push(ch);
    }
    truncated
}

fn session_audit_actor_context(session: &BusinessOsSession) -> Value {
    if let Some(user) = &session.user {
        return serde_json::json!({
            "id": user.id,
            "display_name": user.display_name,
            "role": user.role,
            "trusted": true
        });
    }
    serde_json::json!({
        "id": "business-os-session",
        "display_name": "Business OS Session",
        "trusted": false
    })
}

fn business_user_audit_snapshot(conn: &Connection, user_id: &str) -> anyhow::Result<Option<Value>> {
    conn.query_row(
        "SELECT user_id, display_name, role, active
         FROM business_users
         WHERE user_id = ?1",
        params![user_id],
        |row| {
            Ok(serde_json::json!({
                "id": row.get::<_, String>(0)?,
                "display_name": row.get::<_, String>(1)?,
                "role": row.get::<_, String>(2)?,
                "active": row.get::<_, i64>(3)? != 0
            }))
        },
    )
    .optional()
    .map_err(Into::into)
}

fn module_founder_audit_snapshot(
    conn: &Connection,
    module_id: &str,
    user_id: &str,
) -> anyhow::Result<Option<Value>> {
    conn.query_row(
        "SELECT module_id, user_id, role, active
         FROM business_module_acl
         WHERE module_id = ?1 AND user_id = ?2 AND role = 'founder'",
        params![module_id, user_id],
        |row| {
            let module_id: String = row.get(0)?;
            let user_id: String = row.get(1)?;
            let role: String = row.get(2)?;
            Ok(serde_json::json!({
                "id": format!("{module_id}:founder:{user_id}"),
                "module_id": module_id,
                "user_id": user_id,
                "role": role,
                "active": row.get::<_, i64>(3)? != 0
            }))
        },
    )
    .optional()
    .map_err(Into::into)
}

fn changed_fields(previous: Option<&Value>, current: &Value, fields: &[&str]) -> Vec<Value> {
    fields
        .iter()
        .filter(|field| {
            previous
                .and_then(|value| value.get(*field))
                .unwrap_or(&Value::Null)
                != current.get(*field).unwrap_or(&Value::Null)
        })
        .map(|field| Value::String((*field).to_owned()))
        .collect()
}

fn record_business_user_change_event(
    conn: &Connection,
    session: &BusinessOsSession,
    previous: Option<&Value>,
    current: &Value,
    observed_at_ms: i64,
) -> anyhow::Result<()> {
    let user_id = current
        .get("id")
        .and_then(Value::as_str)
        .context("business user audit id is required")?;
    insert_business_event(
        conn,
        "business_users",
        user_id,
        "business_os.user.changed",
        serde_json::json!({
            "event_type": "business_os.user.changed",
            "user_id": user_id,
            "actor": session_audit_actor_context(session),
            "previous": previous.cloned(),
            "current": current,
            "changed_fields": changed_fields(previous, current, &[
                "display_name",
                "role",
                "active"
            ]),
            "observed_at_ms": observed_at_ms
        }),
        observed_at_ms,
    )
}

fn record_module_founder_change_event(
    conn: &Connection,
    session: &BusinessOsSession,
    previous: Option<&Value>,
    current: &Value,
    observed_at_ms: i64,
) -> anyhow::Result<()> {
    let record_id = current
        .get("id")
        .and_then(Value::as_str)
        .context("module founder audit id is required")?;
    insert_business_event(
        conn,
        "business_module_acl",
        record_id,
        "business_os.app_responsibility.changed",
        serde_json::json!({
            "event_type": "business_os.app_responsibility.changed",
            "module_id": current.get("module_id").and_then(Value::as_str),
            "user_id": current.get("user_id").and_then(Value::as_str),
            "actor": session_audit_actor_context(session),
            "previous": previous.cloned(),
            "current": current,
            "changed_fields": changed_fields(previous, current, &["active"]),
            "observed_at_ms": observed_at_ms
        }),
        observed_at_ms,
    )
}

fn reject_command_if_policy_denied(
    root: &Path,
    command: &BusinessCommand,
    decision: &PolicyDecision,
) -> anyhow::Result<Option<Value>> {
    if decision.allowed {
        if should_record_allowed_policy_decision(command) {
            record_business_policy_decision_event(root, command, decision)?;
        }
        return Ok(None);
    }
    Ok(Some(write_rxdb_policy_denied_command_outcome(
        root, command, decision,
    )?))
}

fn should_record_allowed_policy_decision(command: &BusinessCommand) -> bool {
    !matches!(command.command_type.as_str(), "ctox.business_os.audit.list")
}

fn workspace_policy_decision(
    root: &Path,
    session: &BusinessOsSession,
    permission: BusinessOsPermission,
) -> anyhow::Result<PolicyDecision> {
    scoped_policy_decision(root, session, permission, BusinessOsScope::workspace())
}

fn owner_transfer_policy_decision(session: &BusinessOsSession) -> PolicyDecision {
    let actor = policy_actor_from_session(session);
    policy::evaluate(
        &actor,
        BusinessOsPermission::WorkspaceManage,
        &BusinessOsScope::workspace(),
    )
}

fn user_upsert_policy_decision(
    root: &Path,
    session: &BusinessOsSession,
    target_role: &str,
) -> anyhow::Result<PolicyDecision> {
    let decision = workspace_policy_decision(root, session, BusinessOsPermission::UsersManage)?;
    if !decision.allowed || target_role != "chef" {
        return Ok(decision);
    }
    Ok(owner_transfer_policy_decision(session))
}

fn task_policy_decision(
    root: &Path,
    session: &BusinessOsSession,
    task_id: &str,
) -> anyhow::Result<PolicyDecision> {
    scoped_policy_decision(
        root,
        session,
        BusinessOsPermission::CtoxTaskManage,
        BusinessOsScope::task(task_id.trim(), false, false),
    )
}

pub fn process_source_parse_command(
    root: &Path,
    command_id: &str,
) -> anyhow::Result<CommandAccepted> {
    let conn = open_store(root)?;
    let command = load_business_command(&conn, command_id)?;
    anyhow::ensure!(
        is_source_parse_command(&command.command_type)
            || is_match_command(&command.command_type)
            || is_outbound_research_command(&command.command_type)
            || is_documents_report_command(&command),
        "business command {command_id} is not a supported Business OS harness command"
    );
    let queue_task = find_queue_task_for_command(root, command_id)
        .and_then(|task_id| channels::load_queue_task(root, &task_id).ok().flatten());

    if is_documents_report_command(&command) {
        return process_documents_report_command(
            root,
            &conn,
            command_id,
            &command,
            queue_task.as_ref(),
            None,
        );
    }

    let result = if is_source_parse_command(&command.command_type) {
        super::importer::handle_source_parse(root, &conn, command_id, &command, queue_task.as_ref())
    } else {
        if is_outbound_research_command(&command.command_type) {
            super::importer::handle_outbound_research(
                root,
                &conn,
                command_id,
                &command,
                queue_task.as_ref(),
            )
        } else {
            super::importer::handle_match_compute(
                root,
                &conn,
                command_id,
                &command,
                queue_task.as_ref(),
            )
        }
    };

    match result {
        Ok(outcome) => {
            let completed_at_ms = now_ms() as i64;
            conn.execute(
                "UPDATE business_commands SET status = 'completed', observed_at_ms = ?2 WHERE command_id = ?1",
                params![command_id, completed_at_ms],
            )?;
            let updated_queue_task = if let Some(task) = &queue_task {
                Some(channels::update_queue_task(
                    root,
                    channels::QueueTaskUpdateRequest {
                        message_key: task.message_key.clone(),
                        route_status: Some("handled".to_string()),
                        status_note: Some(format!(
                            "business-os:terminal-success: command completed: {} record(s)",
                            outcome.records_count
                        )),
                        ..Default::default()
                    },
                )?)
            } else {
                None
            };
            let command_payload = serde_json::json!({
                "id": command_id,
                "command_id": command_id,
                "module": command.module.clone(),
                "command_type": command.command_type.clone(),
                "record_id": command.record_id.clone().unwrap_or_default(),
                "status": "completed",
                "inbound_channel": command_inbound_channel(&command),
                "task_id": queue_task.as_ref().map(|task| task.message_key.clone()),
                "task_status": "completed",
                "payload": command.payload.clone(),
                "client_context": command.client_context.clone(),
                "result": {
                    "record_ids": outcome.record_ids,
                    "records_count": outcome.records_count,
                    "collection": outcome.collection,
                    "definition_id": outcome.definition_id
                },
                "updated_at_ms": completed_at_ms
            });
            upsert_business_record(
                &conn,
                "business_commands",
                command_id,
                completed_at_ms,
                command_payload.clone(),
            )?;
            let mut rxdb_writers = RxdbProjectionWriterCache::new(root);
            upsert_rxdb_collection_record_cached(
                root,
                Some(&mut rxdb_writers),
                "business_commands",
                command_id,
                completed_at_ms,
                command_payload,
            )?;
            refresh_queue_task_projection(
                root,
                &conn,
                Some(&mut rxdb_writers),
                command_id,
                &command,
                updated_queue_task.as_ref().or(queue_task.as_ref()),
                completed_at_ms,
            )?;
            Ok(CommandAccepted {
                ok: true,
                command_id: command_id.to_string(),
                status: "completed",
                task_id: queue_task.as_ref().map(|task| task.message_key.clone()),
                task_status: Some("completed".to_string()),
            })
        }
        Err(err) => {
            let failed_at_ms = now_ms() as i64;
            conn.execute(
                "UPDATE business_commands SET status = 'failed', observed_at_ms = ?2 WHERE command_id = ?1",
                params![command_id, failed_at_ms],
            )?;
            let updated_queue_task = if let Some(task) = &queue_task {
                Some(channels::update_queue_task(
                    root,
                    channels::QueueTaskUpdateRequest {
                        message_key: task.message_key.clone(),
                        route_status: Some("failed".to_string()),
                        status_note: Some(err.to_string()),
                        ..Default::default()
                    },
                )?)
            } else {
                None
            };
            let command_payload = serde_json::json!({
                "id": command_id,
                "command_id": command_id,
                "module": command.module.clone(),
                "command_type": command.command_type.clone(),
                "record_id": command.record_id.clone().unwrap_or_default(),
                "status": "failed",
                "inbound_channel": command_inbound_channel(&command),
                "task_id": queue_task.as_ref().map(|task| task.message_key.clone()),
                "task_status": "failed",
                "error": err.to_string(),
                "payload": command.payload.clone(),
                "client_context": command.client_context.clone(),
                "updated_at_ms": failed_at_ms
            });
            upsert_business_record(
                &conn,
                "business_commands",
                command_id,
                failed_at_ms,
                command_payload.clone(),
            )?;
            let mut rxdb_writers = RxdbProjectionWriterCache::new(root);
            upsert_rxdb_collection_record_cached(
                root,
                Some(&mut rxdb_writers),
                "business_commands",
                command_id,
                failed_at_ms,
                command_payload,
            )?;
            refresh_queue_task_projection(
                root,
                &conn,
                Some(&mut rxdb_writers),
                command_id,
                &command,
                updated_queue_task.as_ref().or(queue_task.as_ref()),
                failed_at_ms,
            )?;
            Ok(CommandAccepted {
                ok: false,
                command_id: command_id.to_string(),
                status: "failed",
                task_id: queue_task.as_ref().map(|task| task.message_key.clone()),
                task_status: Some("failed".to_string()),
            })
        }
    }
}

pub fn complete_business_command_from_queue_reply(
    root: &Path,
    task_id: &str,
    reply_text: &str,
) -> anyhow::Result<Option<Value>> {
    let conn = open_store(root)?;
    let Some(command_id) = queue_projection_command_id(&conn, task_id)? else {
        return Ok(None);
    };
    let command = load_business_command(&conn, &command_id)?;
    let queue_task = channels::load_queue_task(root, task_id)?;
    let accepted = if is_documents_report_command(&command) {
        process_documents_report_command(
            root,
            &conn,
            &command_id,
            &command,
            queue_task.as_ref(),
            Some(reply_text),
        )?
    } else if is_systematic_research_command(&command) {
        process_systematic_research_command(
            root,
            &conn,
            &command_id,
            &command,
            queue_task.as_ref(),
            reply_text,
        )?
    } else if is_cv_print_parse_command(&command) {
        process_cv_print_parse_command(
            root,
            &conn,
            &command_id,
            &command,
            queue_task.as_ref(),
            Some(reply_text),
        )?
    } else if is_business_chat_command(&command) {
        process_business_chat_reply(
            root,
            &conn,
            &command_id,
            &command,
            queue_task.as_ref(),
            reply_text,
        )?
    } else {
        return Ok(None);
    };
    Ok(Some(serde_json::to_value(accepted)?))
}

pub fn complete_cv_print_command_from_reply(
    root: &Path,
    command_id: &str,
    task_id: Option<&str>,
    reply_text: &str,
) -> anyhow::Result<Option<Value>> {
    let conn = open_store(root)?;
    let command_id = command_id.trim();
    if command_id.is_empty() {
        return Ok(None);
    }
    let command = load_business_command(&conn, command_id)?;
    if !is_cv_print_parse_command(&command) {
        return Ok(None);
    }
    let queue_task = if let Some(task_id) = task_id {
        channels::load_queue_task(root, task_id)?
    } else {
        find_queue_task_for_command(root, command_id)
            .and_then(|found| channels::load_queue_task(root, &found).ok().flatten())
    };
    let accepted = process_cv_print_parse_command(
        root,
        &conn,
        command_id,
        &command,
        queue_task.as_ref(),
        Some(reply_text),
    )?;
    Ok(Some(serde_json::to_value(accepted)?))
}

pub fn complete_business_command_from_app_validation_success(
    root: &Path,
    task_id: &str,
    expected_module_id: Option<&str>,
    reason: &str,
) -> anyhow::Result<Option<Value>> {
    let conn = open_store(root)?;
    let Some(command_id) = queue_projection_command_id(&conn, task_id)? else {
        return Ok(None);
    };
    let command = load_business_command(&conn, &command_id)?;
    let Some((module_id, install_target, artifact_directory)) =
        business_os_app_command_target_metadata(&command)
    else {
        return Ok(None);
    };
    if let Some(expected_module_id) = expected_module_id {
        anyhow::ensure!(
            module_id == expected_module_id,
            "queue task `{task_id}` belongs to Business OS app module `{module_id}`, not `{expected_module_id}`"
        );
    }
    let mut terminal_queue_task = channels::load_queue_task(root, task_id)?;
    let completed_at_ms = now_ms() as i64;
    ensure_app_create_actor_lifecycle_assignment(
        root,
        &conn,
        &command,
        &module_id,
        &install_target,
        completed_at_ms,
    )?;
    write_module_catalog_projection_to_rxdb_for_module(root, &module_id)?;
    let native_schema_refresh =
        refresh_native_peer_after_runtime_app_schema_change(root, &module_id, &install_target)?;
    conn.execute(
        "UPDATE business_commands SET status = 'completed', observed_at_ms = ?2 WHERE command_id = ?1",
        params![command_id.as_str(), completed_at_ms],
    )?;

    if let Some(task) = terminal_queue_task.as_ref() {
        let message_key = task.message_key.clone();
        let status_note = "business-os:terminal-success: app validation passed";
        channels::ack_leased_messages_with_reason(
            root,
            std::slice::from_ref(&message_key),
            "handled",
            status_note,
        )
        .or_else(|ack_err| {
            channels::update_queue_task(
                root,
                channels::QueueTaskUpdateRequest {
                    message_key: message_key.clone(),
                    route_status: Some("handled".to_string()),
                    status_note: Some(status_note.to_string()),
                    ..Default::default()
                },
            )
            .map(|_| 1usize)
            .with_context(|| {
                format!(
                    "failed to mark app-validation queue task `{message_key}` handled after ack failed: {ack_err}"
                )
            })
        })?;
        if let Err(err) = channels::update_queue_task(
            root,
            channels::QueueTaskUpdateRequest {
                message_key: message_key.clone(),
                status_note: Some(status_note.to_string()),
                ..Default::default()
            },
        ) {
            eprintln!(
                "[business-os] failed to attach app validation success note to `{message_key}`: {err:#}"
            );
        }
        terminal_queue_task =
            channels::load_queue_task(root, task_id)?.or_else(|| terminal_queue_task.clone());
    }

    let task_status = terminal_queue_task
        .as_ref()
        .map(|task| normalize_queue_status(&task.route_status).to_string())
        .unwrap_or_else(|| "completed".to_string());
    let command_payload = serde_json::json!({
        "id": command_id,
        "command_id": command_id,
        "module": command.module.clone(),
        "command_type": command.command_type.clone(),
        "record_id": command.record_id.clone().unwrap_or_default(),
        "status": "completed",
        "inbound_channel": command_inbound_channel(&command),
        "task_id": task_id,
        "task_status": task_status,
        "payload": command.payload.clone(),
        "client_context": command.client_context.clone(),
        "result": {
            "module_id": module_id,
            "install_target": install_target,
            "artifact_directory": artifact_directory,
            "validator": "business_os_app_module_validator",
            "validation_status": "passed",
            "completion_reason": reason,
            "native_schema_refresh": native_schema_refresh
        },
        "updated_at_ms": completed_at_ms
    });
    upsert_business_record(
        &conn,
        "business_commands",
        &command_id,
        completed_at_ms,
        command_payload.clone(),
    )?;
    let mut rxdb_writers = RxdbProjectionWriterCache::new(root);
    upsert_rxdb_collection_record_cached(
        root,
        Some(&mut rxdb_writers),
        "business_commands",
        &command_id,
        completed_at_ms,
        command_payload.clone(),
    )?;
    refresh_queue_task_projection(
        root,
        &conn,
        Some(&mut rxdb_writers),
        &command_id,
        &command,
        terminal_queue_task.as_ref(),
        completed_at_ms,
    )?;
    Ok(Some(command_payload))
}

fn refresh_native_peer_after_runtime_app_schema_change(
    root: &Path,
    module_id: &str,
    install_target: &str,
) -> anyhow::Result<Value> {
    if install_target != "runtime-installed-module" {
        return Ok(serde_json::json!({
            "required": false,
            "status": "not_runtime_installed"
        }));
    }
    if !super::rxdb_peer::is_native_peer_running() {
        return Ok(serde_json::json!({
            "required": true,
            "status": "deferred_until_native_peer_start",
            "module_id": module_id
        }));
    }
    let restarted = super::rxdb_peer::restart_native_peer(root).with_context(|| {
        format!("failed to refresh native RxDB peer after app `{module_id}` schema change")
    })?;
    Ok(serde_json::json!({
        "required": true,
        "status": "restarted",
        "module_id": module_id,
        "native_peer": restarted
    }))
}

fn ensure_app_create_actor_lifecycle_assignment(
    root: &Path,
    conn: &Connection,
    command: &BusinessCommand,
    module_id: &str,
    install_target: &str,
    observed_at_ms: i64,
) -> anyhow::Result<Option<String>> {
    if command.command_type != "ctox.business_os.app.create"
        || install_target != "runtime-installed-module"
    {
        return Ok(None);
    }
    let session = rxdb_authenticated_session(root, command)?;
    seed_session_user(conn, &session)?;
    let Some(user_id) = session_user_id(&session)
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return Ok(None);
    };
    let assignment_id = upsert_module_founder_assignment_record(
        conn,
        &session,
        module_id,
        user_id,
        true,
        observed_at_ms,
    )?;
    let app_root = resolve_business_os_app_root(root)?;
    let manifest_path = module_manifest_path(root, &app_root, module_id)?;
    let version_app_root = app_root_for_module_manifest(&app_root, &manifest_path);
    record_module_version_with_conn(
        conn,
        &version_app_root,
        module_id,
        "app_create",
        "Initial app creation",
        user_id,
    )?;
    Ok(Some(assignment_id))
}

pub fn complete_ready_documents_report_commands(
    root: &Path,
    limit: usize,
) -> anyhow::Result<usize> {
    with_store_connection(root, |conn| {
        let mut statement = conn.prepare(
            "SELECT command_id
             FROM business_commands
             WHERE module = 'documents'
               AND command_type = 'research.systematic.report.create'
               AND status NOT IN ('completed', 'failed', 'cancelled')
             ORDER BY observed_at_ms ASC, command_id ASC
             LIMIT ?1",
        )?;
        let rows =
            statement.query_map(params![limit.max(1) as i64], |row| row.get::<_, String>(0))?;
        let command_ids = rows.collect::<rusqlite::Result<Vec<_>>>()?;
        drop(statement);

        let mut completed = 0usize;
        for command_id in command_ids {
            let command = match load_business_command(conn, &command_id) {
                Ok(command) => command,
                Err(_) => continue,
            };
            if !is_documents_report_command(&command) {
                continue;
            }
            let Some(filename) = expected_docx_filename(&command) else {
                continue;
            };
            let Some(docx_path) = resolve_generated_docx_path(root, &command, &filename, None)
            else {
                continue;
            };
            if !docx_path.is_file() {
                continue;
            }
            let task = find_queue_task_for_command(root, &command_id)
                .and_then(|task_id| channels::load_queue_task(root, &task_id).ok().flatten());
            let reply = format!(
                "DOCX artifact created and detected by Business OS writeback: {}",
                docx_path.display()
            );
            process_documents_report_command(
                root,
                conn,
                &command_id,
                &command,
                task.as_ref(),
                Some(&reply),
            )?;
            completed += 1;
        }
        Ok(completed)
    })
}

fn process_business_chat_reply(
    root: &Path,
    conn: &Connection,
    command_id: &str,
    command: &BusinessCommand,
    queue_task: Option<&channels::QueueTaskView>,
    reply_text: &str,
) -> anyhow::Result<CommandAccepted> {
    let completed_at_ms = now_ms() as i64;
    conn.execute(
        "UPDATE business_commands SET status = 'completed', observed_at_ms = ?2 WHERE command_id = ?1",
        params![command_id, completed_at_ms],
    )?;

    let mut terminal_queue_task = queue_task.cloned();
    if let Some(task) = queue_task {
        let _ = channels::update_queue_task(
            root,
            channels::QueueTaskUpdateRequest {
                message_key: task.message_key.clone(),
                route_status: Some("handled".to_string()),
                status_note: Some("business-os:terminal-success: chat reply stored".to_string()),
                ..Default::default()
            },
        );
        terminal_queue_task = channels::load_queue_task(root, &task.message_key)
            .ok()
            .flatten()
            .or_else(|| Some(task.clone()));
    }

    let chat_id = business_chat_id(command, command_id);
    let chat_title = business_chat_title(command);
    let owner_user_id = first_string_field(&command.client_context, &["owner_user_id", "user_id"])
        .unwrap_or_else(|| "local-dev".to_string());
    let task_id = terminal_queue_task
        .as_ref()
        .map(|task| task.message_key.clone())
        .unwrap_or_default();
    let user_message_id = first_string_field(&command.payload, &["message_id"])
        .or_else(|| first_string_field(&command.client_context, &["message_id"]))
        .unwrap_or_else(|| format!("chatmsg_{command_id}"));
    let user_text = first_string_field(
        &command.payload,
        &["user_message", "instruction", "prompt", "message"],
    )
    .or_else(|| first_string_field(&command.client_context, &["user_message", "message"]))
    .unwrap_or_else(|| {
        queue_task
            .map(|task| task.prompt.clone())
            .unwrap_or_default()
    });

    let chat_payload = business_chat_payload(
        conn,
        &chat_id,
        &chat_title,
        &owner_user_id,
        &user_message_id,
        &user_text,
        command_id,
        &task_id,
        reply_text,
        completed_at_ms,
    )?;
    upsert_business_record(
        conn,
        "business_chats",
        &chat_id,
        completed_at_ms,
        chat_payload.clone(),
    )?;
    let mut rxdb_writers = RxdbProjectionWriterCache::new(root);
    upsert_rxdb_collection_record_cached(
        root,
        Some(&mut rxdb_writers),
        "business_chats",
        &chat_id,
        completed_at_ms,
        chat_payload,
    )?;

    let command_payload = serde_json::json!({
        "id": command_id,
        "command_id": command_id,
        "module": command.module.clone(),
        "command_type": command.command_type.clone(),
        "record_id": command.record_id.clone().unwrap_or_default(),
        "status": "completed",
        "inbound_channel": command_inbound_channel(command),
        "task_id": task_id,
        "task_status": "completed",
        "payload": command.payload.clone(),
        "client_context": command.client_context.clone(),
        "result": {
            "chat_id": chat_id,
            "outbound_text": reply_text,
            "response": reply_text,
            "answer": reply_text,
            "summary": reply_text
        },
        "outbound_text": reply_text,
        "response": reply_text,
        "answer": reply_text,
        "updated_at_ms": completed_at_ms
    });
    upsert_business_record(
        conn,
        "business_commands",
        command_id,
        completed_at_ms,
        command_payload.clone(),
    )?;
    upsert_rxdb_collection_record_cached(
        root,
        Some(&mut rxdb_writers),
        "business_commands",
        command_id,
        completed_at_ms,
        command_payload,
    )?;
    refresh_queue_task_projection(
        root,
        conn,
        Some(&mut rxdb_writers),
        command_id,
        command,
        terminal_queue_task.as_ref(),
        completed_at_ms,
    )?;

    Ok(CommandAccepted {
        ok: true,
        command_id: command_id.to_string(),
        status: "completed",
        task_id: terminal_queue_task.map(|task| task.message_key.clone()),
        task_status: Some("completed".to_string()),
    })
}

pub fn pull_collection_records(
    root: &Path,
    collection: &str,
    since_ms: Option<i64>,
    limit: Option<usize>,
) -> anyhow::Result<Value> {
    let projected = pull_collection_records_for_projection(root, collection, since_ms, limit)?;
    let documents_are_empty = projected
        .get("documents")
        .and_then(Value::as_array)
        .map_or(true, Vec::is_empty);
    if documents_are_empty {
        let since_ms = since_ms.unwrap_or(0);
        let limit = limit.unwrap_or(500).clamp(1, 2_000);
        if let Some(rxdb_projection) =
            pull_rxdb_collection_table_records(root, collection, since_ms, limit)?
        {
            return Ok(rxdb_projection);
        }
    }
    Ok(projected)
}

pub fn pull_collection_records_for_projection(
    root: &Path,
    collection: &str,
    since_ms: Option<i64>,
    limit: Option<usize>,
) -> anyhow::Result<Value> {
    // Conversations module reads communication_* collections. These live in
    // CTOX's channels SQLite (runtime/ctox.sqlite3), not in business-os.sqlite3 —
    // so we delegate to channels.rs helpers that read from the canonical tables
    // directly. No projection table needed; messages/threads/accounts stay
    // single-source-of-truth in channels.
    match collection {
        "ctox_runtime_settings" => {
            return pull_runtime_settings_records(root, since_ms, limit);
        }
        "business_workspace_branding" => {
            return pull_workspace_branding_records(root, since_ms, limit);
        }
        "communication_accounts" => {
            return channels::pull_communication_accounts_for_business_os(root, since_ms, limit);
        }
        "communication_threads" => {
            return channels::pull_communication_threads_for_business_os(root, since_ms, limit);
        }
        "communication_messages" => {
            return channels::pull_communication_messages_for_business_os(root, since_ms, limit);
        }
        _ => {}
    }
    let limit = limit.unwrap_or(500).clamp(1, 2_000);
    let since_ms = since_ms.unwrap_or(0);
    let documents = with_store_connection(root, |conn| {
        let mut statement = conn.prepare(
            "SELECT record_id, deleted, updated_at_ms, payload_json
             FROM business_records
             WHERE collection = ?1 AND updated_at_ms >= ?2
             ORDER BY updated_at_ms ASC, record_id ASC
             LIMIT ?3",
        )?;
        let rows = statement.query_map(params![collection, since_ms, limit as i64], |row| {
            let record_id: String = row.get(0)?;
            let deleted: i64 = row.get(1)?;
            let updated_at_ms: i64 = row.get(2)?;
            let payload_json: String = row.get(3)?;
            Ok((record_id, deleted, updated_at_ms, payload_json))
        })?;
        let mut documents = Vec::new();
        for row in rows {
            let (record_id, deleted, updated_at_ms, payload_json) = row?;
            let mut payload = serde_json::from_str::<Value>(&payload_json).unwrap_or(Value::Null);
            if let Some(obj) = payload.as_object_mut() {
                obj.entry("id".to_string())
                    .or_insert_with(|| Value::String(record_id.clone()));
                obj.insert("_deleted".to_string(), Value::Bool(deleted != 0));
                obj.insert("updated_at_ms".to_string(), Value::from(updated_at_ms));
            }
            documents.push(payload);
        }
        Ok(documents)
    })?;
    Ok(serde_json::json!({
        "ok": true,
        "collection": collection,
        "documents": documents,
        "count": documents.len(),
        "since_ms": since_ms,
        "source": "business_records"
    }))
}

pub fn pull_collection_record(
    root: &Path,
    collection: &str,
    record_id: &str,
) -> anyhow::Result<Option<Value>> {
    if collection.trim().is_empty() || record_id.trim().is_empty() {
        return Ok(None);
    }
    match collection {
        "ctox_runtime_settings" if record_id == "runtime-settings" => {
            return Ok(Some(runtime_settings_for_rxdb(root)?));
        }
        "business_workspace_branding" if record_id == WORKSPACE_BRANDING_ID => {
            return Ok(Some(workspace_branding_for_rxdb(root)?));
        }
        "communication_accounts" | "communication_threads" | "communication_messages" => {
            return channels::pull_communication_record_for_business_os(
                root, collection, record_id,
            );
        }
        _ => {}
    }
    let payload_json = with_store_connection(root, |conn| {
        Ok(conn
            .query_row(
                "SELECT payload_json FROM business_records
                 WHERE collection = ?1 AND record_id = ?2 AND deleted = 0",
                params![collection, record_id],
                |row| row.get::<_, String>(0),
            )
            .optional()?)
    })?;
    if let Some(payload_json) = payload_json {
        let mut payload = serde_json::from_str::<Value>(&payload_json).unwrap_or(Value::Null);
        if let Some(object) = payload.as_object_mut() {
            object
                .entry("id".to_string())
                .or_insert_with(|| Value::String(record_id.to_string()));
            object.insert("_deleted".to_string(), Value::Bool(false));
        }
        return Ok(Some(payload));
    }
    load_rxdb_collection_record(root, collection, record_id)
}

fn pull_runtime_settings_records(
    root: &Path,
    since_ms: Option<i64>,
    limit: Option<usize>,
) -> anyhow::Result<Value> {
    let limit = limit.unwrap_or(500).clamp(1, 2_000);
    let since_ms = since_ms.unwrap_or(0);
    let document = runtime_settings_for_rxdb(root)?;
    let updated_at_ms = document
        .get("updated_at_ms")
        .and_then(Value::as_i64)
        .unwrap_or(0);
    let documents = if limit == 0 || updated_at_ms < since_ms {
        Vec::new()
    } else {
        vec![document]
    };
    Ok(serde_json::json!({
        "ok": true,
        "collection": "ctox_runtime_settings",
        "documents": documents,
        "count": documents.len(),
        "since_ms": since_ms,
        "source": "native_runtime_projection"
    }))
}

