fn stored_rxdb_business_command_outcome(
    conn: &Connection,
    command_id: &str,
) -> anyhow::Result<Option<Value>> {
    let payload_json: Option<String> = conn
        .query_row(
            "SELECT payload_json
             FROM business_records
             WHERE collection = 'business_commands'
               AND record_id = ?1
               AND deleted = 0",
            params![command_id],
            |row| row.get(0),
        )
        .optional()?;

    let Some(payload_json) = payload_json else {
        return Ok(None);
    };
    let mut payload: Value = serde_json::from_str(&payload_json)
        .with_context(|| format!("invalid stored business command projection for {command_id}"))?;
    if let Some(obj) = payload.as_object_mut() {
        obj.insert("ok".to_string(), Value::Bool(true));
        obj.insert("id".to_string(), Value::String(command_id.to_string()));
        obj.insert(
            "command_id".to_string(),
            Value::String(command_id.to_string()),
        );
        obj.insert("already_accepted".to_string(), Value::Bool(true));
    }
    Ok(Some(payload))
}

const CAPABILITY_SECRET_SCOPE: &str = "credentials";
const CAPABILITY_SECRET_NAME: &str = "BUSINESS_OS_CAPABILITY_SECRET";
/// Default capability-token lifetime (12h) — short enough to bound a leaked
/// token, long enough for a working session.
const CAPABILITY_TOKEN_TTL_MS: i64 = 12 * 60 * 60 * 1000;

/// Get (or generate + persist) the per-instance HMAC secret that signs Business
/// OS capability tokens. Stored in the CTOX secret store so it survives restarts
/// and is never shipped to the browser.
fn capability_signing_secret(root: &Path) -> anyhow::Result<Vec<u8>> {
    if crate::secrets::secret_exists(root, CAPABILITY_SECRET_SCOPE, CAPABILITY_SECRET_NAME)? {
        let value = crate::secrets::read_secret_value(
            root,
            CAPABILITY_SECRET_SCOPE,
            CAPABILITY_SECRET_NAME,
        )?;
        if !value.trim().is_empty() {
            return Ok(value.into_bytes());
        }
    }
    use ring::rand::SecureRandom;
    let mut buf = [0u8; 32];
    ring::rand::SystemRandom::new()
        .fill(&mut buf)
        .map_err(|_| anyhow::anyhow!("failed to generate capability signing secret"))?;
    let value = base64::engine::general_purpose::STANDARD.encode(buf);
    crate::secrets::write_secret_record(
        root,
        CAPABILITY_SECRET_SCOPE,
        CAPABILITY_SECRET_NAME,
        &value,
        Some("Business OS capability-token HMAC secret (auto-generated)".to_string()),
        serde_json::json!({ "auto_managed": true }),
    )?;
    Ok(value.into_bytes())
}

/// Verify a Business OS capability token and return its actor role, or `None`
/// if the token is missing, malformed or expired. Binds a sync-mesh browser
/// peer to its server-authenticated role for the per-collection authz gate.
pub fn verify_capability_role(root: &Path, token: &str) -> Option<String> {
    let token = token.trim();
    if token.is_empty() {
        return None;
    }
    let secret = capability_signing_secret(root).ok()?;
    super::capability::verify_capability_token(&secret, token, now_ms() as i64)
        .map(|claims| claims.role)
}

pub fn verify_capability_actor(root: &Path, token: &str) -> Option<(String, String)> {
    let token = token.trim();
    if token.is_empty() {
        return None;
    }
    let secret = capability_signing_secret(root).ok()?;
    super::capability::verify_capability_token(&secret, token, now_ms() as i64)
        .map(|claims| (claims.user_id, claims.role))
}

/// Whether server-authoritative per-collection sync authorization is enforced.
/// Default ON: the policy matrix is deny-by-exception for admin-only
/// collections, and browsers now carry native-signed capability tokens in the
/// WebRTC handshake. Operators can still opt out through typed runtime config
/// during legacy rollout, but absence of config must not leave sync fail-open.
pub fn collection_authz_enabled(root: &Path) -> bool {
    !matches!(
        crate::inference::runtime_env::env_or_config(root, "CTOX_BUSINESS_OS_COLLECTION_AUTHZ")
            .as_deref()
            .map(str::trim)
            .map(str::to_ascii_lowercase)
            .as_deref(),
        Some("0" | "false" | "off" | "no")
    )
}

/// Issue a capability token for an active Business OS user, binding their id to
/// their CURRENT server-side role. This is the native-authoritative step: a
/// browser obtains one of these after authenticating and then carries it on
/// every command so the native side can trust the role without trusting the
/// browser-asserted actor. Returns `(token, expires_at_ms)`.
pub fn issue_business_os_capability_token(
    root: &Path,
    user_id: &str,
    now_ms: i64,
) -> anyhow::Result<(String, i64)> {
    let conn = open_store(root)?;
    seed_configured_business_users(&conn)?;
    let user = active_business_user(&conn, user_id.trim())?
        .ok_or_else(|| anyhow::anyhow!("no active Business OS user {user_id:?}"))?;
    let secret = capability_signing_secret(root)?;
    let expires_at_ms = now_ms + CAPABILITY_TOKEN_TTL_MS;
    let token = super::capability::issue_capability_token(
        &secret,
        &user.id,
        &normalize_business_role(&user.role),
        now_ms,
        expires_at_ms,
    );
    Ok((token, expires_at_ms))
}

/// Issue a capability token for a trusted managed-control-plane session.
///
/// ctox.dev authenticates the tenant user on the managed subdomain, then calls
/// this path locally over the instance SSH control plane. This keeps Business OS
/// records on RxDB/WebRTC while allowing the browser command bus to carry a
/// native-signed role token instead of a spoofable actor claim.
pub fn issue_business_os_capability_token_for_managed_user(
    root: &Path,
    user_id: &str,
    display_name: &str,
    role: &str,
    now_ms: i64,
) -> anyhow::Result<(String, i64)> {
    let user_id = user_id.trim();
    anyhow::ensure!(!user_id.is_empty(), "user id is required");
    let role = normalize_business_role(role);
    anyhow::ensure!(
        matches!(role.as_str(), "chef" | "admin" | "founder" | "user"),
        "role must be chef, admin, founder, or user"
    );
    let conn = open_store(root)?;
    seed_configured_business_users(&conn)?;
    let display_name = display_name.trim();
    let display_name = if display_name.is_empty() {
        user_id
    } else {
        display_name
    };
    conn.execute(
        "INSERT INTO business_users
            (user_id, display_name, role, active, created_at_ms, updated_at_ms)
         VALUES (?1, ?2, ?3, 1, ?4, ?4)
         ON CONFLICT(user_id) DO UPDATE SET
            display_name = excluded.display_name,
            role = excluded.role,
            active = 1,
            updated_at_ms = excluded.updated_at_ms",
        params![user_id, display_name, role.as_str(), now_ms],
    )?;
    issue_business_os_capability_token(root, user_id, now_ms)
}

fn rxdb_command_session(
    root: &Path,
    command: &BusinessCommand,
) -> anyhow::Result<BusinessOsSession> {
    rxdb_session_from_command(root, command, true)
}

fn rxdb_authenticated_session(
    root: &Path,
    command: &BusinessCommand,
) -> anyhow::Result<BusinessOsSession> {
    rxdb_session_from_command(root, command, false)
}

// SECURITY (per-command authorization trust boundary):
// The actor in `client_context` is asserted by the command author. For commands
// replicated over the WebRTC/RxDB data plane (`CommandOrigin::ReplicatedPeer`)
// that author is an untrusted browser peer admitted to the room only by the
// shared signaling secret, so its identity and role MUST come from a verified,
// native-signed capability token — never from the claimed actor. Without a valid
// token a replicated command resolves to an unprivileged, non-attributable
// principal (or is rejected outright when the operator requires tokens), so a
// spoofed chef/admin id cannot escalate. In-process commands (`TrustedLocal`:
// operator CLI, server-side handlers that already authenticated a session,
// internal projections) may trust their claimed actor. See `capability.rs`.
fn rxdb_session_from_command(
    root: &Path,
    command: &BusinessCommand,
    require_manage_all: bool,
) -> anyhow::Result<BusinessOsSession> {
    let client_ctx = if let Value::String(ref s) = command.client_context {
        serde_json::from_str(s).unwrap_or_else(|_| command.client_context.clone())
    } else {
        command.client_context.clone()
    };
    let actor = client_ctx.get("actor").or_else(|| client_ctx.get("user"));
    let id = actor
        .and_then(|value| value.get("id"))
        .or_else(|| client_ctx.get("user_id"))
        .and_then(Value::as_str)
        .unwrap_or("rxdb-command")
        .to_string();
    let display_name = actor
        .and_then(|value| value.get("display_name"))
        .or_else(|| actor.and_then(|value| value.get("name")))
        .or_else(|| client_ctx.get("display_name"))
        .and_then(Value::as_str)
        .unwrap_or(id.as_str())
        .to_string();

    // Capability token (native-authoritative): when the command carries a valid
    // native-signed `capability_token`, the id + role come from the SIGNED token
    // for ANY origin, never from the claimed actor.
    let now = now_ms() as i64;
    let verified = client_ctx
        .get("capability_token")
        .and_then(Value::as_str)
        .filter(|token| !token.is_empty())
        .and_then(|token| {
            let secret = capability_signing_secret(root).ok()?;
            super::capability::verify_capability_token(&secret, token, now)
        });

    let (id, role, display_name) = if let Some(claims) = verified {
        (claims.user_id, claims.role, display_name)
    } else {
        match command.origin {
            // Operator / in-process caller: the claimed actor is trusted.
            CommandOrigin::TrustedLocal => {
                let trusted_user = trusted_rxdb_command_user(root, &id, &display_name)?;
                (id, trusted_user.role, trusted_user.display_name)
            }
            // Untrusted browser peer with no verified token. Fail closed: if the
            // operator requires tokens, reject; otherwise resolve an unprivileged,
            // non-attributable principal that matches no role check, founder ACL
            // or id-keyed permission grant — so a spoofed chef/admin id is inert.
            // Legitimate browsers always attach a token (see command-bus.js); this
            // only degrades a client that lost the control plane, never escalates.
            CommandOrigin::ReplicatedPeer => {
                let require_token = crate::inference::runtime_env::env_or_config(
                    root,
                    "CTOX_BUSINESS_OS_REQUIRE_CAPABILITY_TOKEN",
                )
                .as_deref()
                    == Some("1");
                anyhow::ensure!(
                    !require_token,
                    "a valid capability token is required for Business OS commands"
                );
                (
                    "rxdb-command".to_string(),
                    "user".to_string(),
                    "rxdb-command".to_string(),
                )
            }
        }
    };
    let is_admin = role_can_manage(&role);
    let session = BusinessOsSession {
        ok: true,
        authenticated: true,
        auth_required: false,
        user: Some(BusinessOsSessionUser {
            id,
            display_name,
            role,
            is_admin,
        }),
        login_url: None,
        reason: None,
    };
    if require_manage_all {
        anyhow::ensure!(
            session_can_manage_all(&session),
            "chef or admin role required"
        );
    }
    Ok(session)
}

fn trusted_rxdb_command_user(
    root: &Path,
    actor_id: &str,
    actor_display_name: &str,
) -> anyhow::Result<BusinessOsUser> {
    let actor_id = actor_id.trim();
    let conn = open_store(root)?;
    seed_configured_business_users(&conn)?;
    if let Some(user) = active_business_user(&conn, actor_id)? {
        return Ok(user);
    }

    let user_count: i64 =
        conn.query_row("SELECT COUNT(*) FROM business_users", [], |row| row.get(0))?;
    if user_count == 0 && env::var("CTOX_BUSINESS_OS_REQUIRE_LOGIN").as_deref() != Ok("1") {
        let local = session(None, None);
        if let Some(user) = local.user {
            return Ok(BusinessOsUser {
                id: if actor_id.is_empty() {
                    user.id
                } else {
                    actor_id.to_owned()
                },
                display_name: if actor_display_name.trim().is_empty() {
                    user.display_name
                } else {
                    actor_display_name.to_owned()
                },
                role: normalize_business_role(&user.role),
                active: true,
                created_at_ms: 0,
                updated_at_ms: 0,
            });
        }
    }

    Ok(BusinessOsUser {
        id: if actor_id.is_empty() {
            "rxdb-command".to_owned()
        } else {
            actor_id.to_owned()
        },
        display_name: if actor_display_name.trim().is_empty() {
            actor_id.to_owned()
        } else {
            actor_display_name.to_owned()
        },
        role: "user".to_owned(),
        active: true,
        created_at_ms: 0,
        updated_at_ms: 0,
    })
}

fn active_business_user(
    conn: &Connection,
    actor_id: &str,
) -> anyhow::Result<Option<BusinessOsUser>> {
    let actor_id = actor_id.trim();
    if actor_id.is_empty() {
        return Ok(None);
    }
    Ok(conn
        .query_row(
            "SELECT user_id, display_name, role, active, created_at_ms, updated_at_ms
         FROM business_users
         WHERE user_id = ?1 AND active = 1",
            params![actor_id],
            |row| {
                Ok(BusinessOsUser {
                    id: row.get(0)?,
                    display_name: row.get(1)?,
                    role: normalize_business_role(&row.get::<_, String>(2)?),
                    active: row.get::<_, i64>(3)? != 0,
                    created_at_ms: row.get(4)?,
                    updated_at_ms: row.get(5)?,
                })
            },
        )
        .optional()?)
}

fn write_rxdb_control_command_outcome(
    root: &Path,
    command: &BusinessCommand,
    status: &str,
    task_id: Option<&str>,
    task_status: Option<&str>,
    result: Value,
) -> anyhow::Result<Value> {
    let command_id = command.id.as_deref().context("command id is required")?;
    let now = now_ms() as i64;
    let conn = open_store(root)?;
    conn.execute(
        "INSERT INTO business_commands
            (command_id, module, command_type, record_id, status, payload_json, client_context_json, observed_at_ms)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)",
        params![
            command_id,
            command.module,
            command.command_type,
            command.record_id.clone().unwrap_or_default(),
            status,
            serde_json::to_string(&command.payload)?,
            serde_json::to_string(&command.client_context)?,
            now
        ],
    )?;
    let projection = serde_json::json!({
        "id": command_id,
        "command_id": command_id,
        "module": command.module.clone(),
        "command_type": command.command_type.clone(),
        "record_id": command.record_id.clone().unwrap_or_default(),
        "status": status,
        "inbound_channel": command_inbound_channel(command),
        "task_id": task_id.unwrap_or_default(),
        "task_status": task_status.unwrap_or(status),
        "payload": command.payload.clone(),
        "client_context": command.client_context.clone(),
        "result": result.clone(),
        "updated_at_ms": now
    });
    upsert_business_record(
        &conn,
        "business_commands",
        command_id,
        now,
        projection.clone(),
    )?;
    record_business_module_lifecycle_event(root, command, status, &result)?;
    upsert_rxdb_collection_record(root, "business_commands", command_id, now, projection)?;
    Ok(serde_json::json!({
        "ok": true,
        "id": command_id,
        "command_id": command_id,
        "status": status,
        "task_id": task_id.unwrap_or_default(),
        "task_status": task_status.unwrap_or(status),
        "result": result
    }))
}

fn is_customers_active_command(command_type: &str) -> bool {
    matches!(
        command_type,
        "customers.account.create"
            | "customers.account.update"
            | "customers.account.archive"
            | "customers.contact.create"
            | "customers.contact.update"
            | "customers.contact.archive"
            | "customers.opportunity.create"
            | "customers.opportunity.update"
            | "customers.opportunity.move_stage"
            | "customers.opportunity.close_won"
            | "customers.opportunity.close_lost"
            | "customers.task.create"
            | "customers.task.update"
            | "customers.task.complete"
            | "customers.note.create"
            | "customers.note.update"
            | "customers.activity.record"
            | "customers.view.save"
            | "customers.import.from_outbound"
            | "customers.dedupe.resolve"
    )
}

fn handle_customers_active_command(
    root: &Path,
    session: &BusinessOsSession,
    command: &BusinessCommand,
) -> anyhow::Result<Value> {
    anyhow::ensure!(
        command.module == "customers",
        "active customers commands require module=customers"
    );
    let now = now_ms() as i64;
    let conn = open_store(root)?;
    match command.command_type.as_str() {
        "customers.account.create" => customers_account_create(&conn, session, command, now),
        "customers.account.update" => customers_account_update(&conn, session, command, now),
        "customers.account.archive" => customers_account_archive(&conn, session, command, now),
        "customers.contact.create" => customers_contact_create(&conn, session, command, now),
        "customers.contact.update" => customers_contact_update(&conn, session, command, now),
        "customers.contact.archive" => customers_contact_archive(&conn, session, command, now),
        "customers.opportunity.create" => {
            customers_opportunity_create(&conn, session, command, now)
        }
        "customers.opportunity.update" => {
            customers_opportunity_update(&conn, session, command, now)
        }
        "customers.opportunity.move_stage" => {
            customers_opportunity_move_stage(&conn, session, command, now)
        }
        "customers.opportunity.close_won" => {
            customers_opportunity_close(&conn, session, command, now, "closed_won")
        }
        "customers.opportunity.close_lost" => {
            customers_opportunity_close(&conn, session, command, now, "closed_lost")
        }
        "customers.task.create" => customers_task_create(&conn, session, command, now),
        "customers.task.update" => customers_task_update(&conn, session, command, now),
        "customers.task.complete" => customers_task_complete(&conn, session, command, now),
        "customers.note.create" => customers_note_create(&conn, session, command, now),
        "customers.note.update" => customers_note_update(&conn, session, command, now),
        "customers.activity.record" => customers_activity_record(&conn, session, command, now),
        "customers.view.save" => customers_view_save(&conn, session, command, now),
        "customers.import.from_outbound" => {
            customers_import_from_outbound(&conn, session, command, now)
        }
        "customers.dedupe.resolve" => customers_dedupe_resolve(&conn, session, command, now),
        other => anyhow::bail!("unsupported customers command type: {other}"),
    }
}

fn customers_account_create(
    conn: &Connection,
    session: &BusinessOsSession,
    command: &BusinessCommand,
    now: i64,
) -> anyhow::Result<Value> {
    let account_id = customers_id_from_command(command, &["account_id", "id"], "acct")?;
    anyhow::ensure!(
        outbound_load_record(conn, "customer_accounts", &account_id)?.is_none(),
        "customer account already exists"
    );
    let mut account = outbound_object_payload(&command.payload);
    customers_put_string(&mut account, "id", account_id.clone());
    customers_require_field(&account, &["name"])?;
    customers_put_default_string(&mut account, "account_status", "active");
    customers_put_default_string(&mut account, "customer_stage", "active");
    customers_put_default_string(&mut account, "health_status", "unknown");
    customers_put_default_string(&mut account, "currency", "EUR");
    customers_put_default_bool(&mut account, "ideal_customer_profile", false);
    customers_put_default_bool(&mut account, "is_deleted", false);
    customers_put_default_object(&mut account, "payload");
    customers_put_default_i64(&mut account, "created_at_ms", now);
    customers_validate_account(&account)?;
    customers_refresh_search_text(&mut account, &["name", "domain", "industry"]);
    upsert_business_record(conn, "customer_accounts", &account_id, now, account.clone())?;
    let activity = customers_write_activity(
        conn,
        session,
        command,
        now,
        CustomersActivity {
            activity_type: "account_created",
            name: "Kunde erstellt",
            account_id: Some(account_id.clone()),
            contact_id: None,
            opportunity_id: None,
            linked_record_type: Some("account"),
            linked_record_id: Some(account_id.clone()),
            linked_record_name: outbound_string(&account, &["name"]),
            properties: serde_json::json!({ "account": account.clone() }),
        },
    )?;
    Ok(serde_json::json!({
        "ok": true,
        "collection": "customer_accounts",
        "account": account,
        "activity": activity,
    }))
}

