    struct EnvRestore {
        values: Vec<(&'static str, Option<String>)>,
    }

    impl EnvRestore {
        fn set(values: &[(&'static str, &'static str)]) -> Self {
            let restore = Self {
                values: values
                    .iter()
                    .map(|(key, _)| (*key, env::var(key).ok()))
                    .collect(),
            };
            for (key, value) in values {
                unsafe {
                    env::set_var(key, value);
                }
            }
            restore
        }
    }

    impl Drop for EnvRestore {
        fn drop(&mut self) {
            for (key, value) in &self.values {
                unsafe {
                    if let Some(value) = value {
                        env::set_var(key, value);
                    } else {
                        env::remove_var(key);
                    }
                }
            }
        }
    }

    #[test]
    fn local_markdown_notes_source_stamp_ignores_unrelated_store_churn() -> anyhow::Result<()> {
        let temp = tempdir()?;
        sync_local_markdown_notes(temp.path())?;

        let first = local_markdown_notes_source_stamp(temp.path())?;
        let second = local_markdown_notes_source_stamp(temp.path())?;
        assert_eq!(first, second);

        let conn = open_store(temp.path())?;
        upsert_business_record(
            &conn,
            "unrelated_notes_churn",
            "row-1",
            now_ms() as i64,
            serde_json::json!({ "id": "row-1", "value": "not a note" }),
        )?;
        drop(conn);
        assert_eq!(
            local_markdown_notes_source_stamp(temp.path())?,
            first,
            "unrelated business_records rows must not wake the notes sync body"
        );

        let notes_dir = temp.path().join("runtime/business-os/notes");
        let note_path = notes_dir.join("scratch.md");
        std::fs::write(&note_path, "# Scratch\n\nchanged\n")?;
        assert_ne!(
            local_markdown_notes_source_stamp(temp.path())?,
            first,
            "markdown file metadata changes must wake the notes sync body"
        );
        Ok(())
    }

    #[test]
    fn local_markdown_notes_source_stamp_uses_covering_metadata_index() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let conn = open_store(temp.path())?;
        for idx in 0..20 {
            let record_id = format!("note-{idx:03}");
            upsert_business_record(
                &conn,
                "notes",
                &record_id,
                1_000 + idx,
                serde_json::json!({
                    "id": record_id,
                    "title": format!("Note {idx}"),
                    "content": "x".repeat(32_000),
                    "updated_at_ms": 1_000 + idx
                }),
            )?;
        }

        let explain_sql = format!("EXPLAIN QUERY PLAN {LOCAL_MARKDOWN_NOTES_DB_STAMP_SQL}");
        let mut stmt = conn.prepare(&explain_sql)?;
        let details = stmt
            .query_map([], |row| row.get::<_, String>(3))?
            .collect::<Result<Vec<_>, _>>()?;
        assert!(
            details.iter().any(|detail| {
                detail.contains("USING COVERING INDEX idx_business_records_notes_stamp")
            }),
            "notes idle stamp must stay on the covering metadata index, got {details:#?}"
        );
        drop(stmt);
        drop(conn);

        let first = local_markdown_notes_source_stamp(temp.path())?;
        assert_eq!(first.note_count, 20);
        assert_eq!(first.latest_note_updated_at_ms, 1_019);

        let conn = open_store(temp.path())?;
        upsert_business_record(
            &conn,
            "notes",
            "note-010",
            30_000,
            serde_json::json!({
                "id": "note-010",
                "title": "Note 10",
                "content": "changed",
                "updated_at_ms": 30_000
            }),
        )?;
        drop(conn);
        let second = local_markdown_notes_source_stamp(temp.path())?;
        assert_ne!(
            first, second,
            "metadata-only stamp must still wake notes sync on real note updates"
        );
        assert_eq!(second.note_count, 20);
        assert_eq!(second.latest_note_updated_at_ms, 30_000);
        Ok(())
    }

    #[test]
    fn business_records_projection_stamp_uses_projection_clock() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let collections = vec![
            "support_notes".to_string(),
            "business_commands".to_string(),
            "notes".to_string(),
        ];
        let conn = open_store(temp.path())?;
        for collection in &collections {
            for idx in 0..3 {
                let record_id = format!("{collection}-{idx}");
                let updated_at_ms = 5_000 + idx;
                upsert_business_record(
                    &conn,
                    collection,
                    &record_id,
                    updated_at_ms,
                    serde_json::json!({
                        "id": record_id,
                        "updated_at_ms": updated_at_ms,
                        "payload": "x".repeat(64_000)
                    }),
                )?;
            }
        }
        upsert_business_record(
            &conn,
            "unrelated_projection_stamp_noise",
            "noise-1",
            99_000,
            serde_json::json!({
                "id": "noise-1",
                "updated_at_ms": 99_000,
                "payload": "x".repeat(64_000)
            }),
        )?;

        let sql = business_records_projection_clock_stamp_query(collections.len())
            .context("projection clock stamp query sql")?;
        let explain_sql = format!("EXPLAIN QUERY PLAN {sql}");
        let mut stmt = conn.prepare(&explain_sql)?;
        let details = stmt
            .query_map(
                params_from_iter(collections.iter().map(String::as_str)),
                |row| row.get::<_, String>(3),
            )?
            .collect::<Result<Vec<_>, _>>()?;
        assert!(
            details
                .iter()
                .any(|detail| { detail.contains("business_records_projection_clock") }),
            "business-record idle stamp must read the projection clock, got {details:#?}"
        );
        drop(stmt);
        drop(conn);

        let first = business_records_projection_stamp(temp.path(), &collections)?;
        assert_eq!(first.row_count, 9);
        assert_eq!(first.latest_updated_at_ms, 5_002);

        let conn = open_store(temp.path())?;
        upsert_business_record(
            &conn,
            "unrelated_projection_stamp_noise",
            "noise-2",
            100_000,
            serde_json::json!({
                "id": "noise-2",
                "updated_at_ms": 100_000
            }),
        )?;
        drop(conn);
        assert_eq!(
            business_records_projection_stamp(temp.path(), &collections)?,
            first,
            "unrelated collections must not wake the generic projection"
        );

        let conn = open_store(temp.path())?;
        upsert_business_record(
            &conn,
            "notes",
            "notes-1",
            30_000,
            serde_json::json!({
                "id": "notes-1",
                "updated_at_ms": 30_000,
                "payload": "changed"
            }),
        )?;
        drop(conn);
        let second = business_records_projection_stamp(temp.path(), &collections)?;
        assert_ne!(
            first, second,
            "tracked collection changes must still wake the generic projection"
        );
        assert_eq!(second.row_count, 9);
        assert_eq!(second.latest_updated_at_ms, 30_000);
        Ok(())
    }

    #[test]
    fn opaque_session_round_trips_and_revokes() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        // Mint an opaque cookie token for a chef actor.
        let token =
            create_business_session(root, "alice", "chef", "Alice", BUSINESS_SESSION_TTL_SECS)?;
        assert!(!token.is_empty());
        // The token never appears in the table; only its hash is stored.
        let conn = open_store(root)?;
        let stored_hashes: Vec<String> = conn
            .prepare("SELECT token_hash FROM business_sessions")?
            .query_map([], |row| row.get::<_, String>(0))?
            .collect::<Result<_, _>>()?;
        assert_eq!(stored_hashes.len(), 1);
        assert_ne!(stored_hashes[0], token, "raw token must not be persisted");
        // The token resolves to an authenticated chef session.
        let resolved = session_from_cookie_token(root, &token)?.expect("session resolves");
        assert!(resolved.authenticated);
        let user = resolved.user.expect("user present");
        assert_eq!(user.id, "alice");
        assert_eq!(user.role, "chef");
        assert!(user.is_admin);
        // An unknown token is rejected.
        assert!(session_from_cookie_token(root, "not-a-real-token")?.is_none());
        // Revoking the token kills the session.
        revoke_business_session(root, &token)?;
        assert!(session_from_cookie_token(root, &token)?.is_none());
        Ok(())
    }

    #[test]
    fn opaque_session_revoke_for_user_kills_all_sessions() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let token_a =
            create_business_session(root, "bob", "user", "Bob", BUSINESS_SESSION_TTL_SECS)?;
        let token_b =
            create_business_session(root, "bob", "user", "Bob", BUSINESS_SESSION_TTL_SECS)?;
        assert!(session_from_cookie_token(root, &token_a)?.is_some());
        assert!(session_from_cookie_token(root, &token_b)?.is_some());
        let revoked = revoke_business_sessions_for_user(root, "bob")?;
        assert_eq!(revoked, 2);
        assert!(session_from_cookie_token(root, &token_a)?.is_none());
        assert!(session_from_cookie_token(root, &token_b)?.is_none());
        Ok(())
    }

    #[test]
    fn ephemeral_turn_credentials_follow_coturn_scheme() {
        let now_ms = 1_000_000_000_000_i64; // 1_000_000_000 s
        let (username, password) = mint_ephemeral_turn_credentials("s3cr3t", "user-1", now_ms);
        // username = "<expiry>:<session>", expiry = now_s + ttl.
        assert_eq!(
            username,
            format!("{}:user-1", 1_000_000_000 + BUSINESS_OS_TURN_TTL_SECS)
        );
        // password is base64 of a 20-byte HMAC-SHA1 digest.
        let decoded = base64::engine::general_purpose::STANDARD
            .decode(&password)
            .expect("password is base64");
        assert_eq!(decoded.len(), 20);
        // Deterministic for identical inputs; secret is the security boundary.
        let (u2, p2) = mint_ephemeral_turn_credentials("s3cr3t", "user-1", now_ms);
        assert_eq!((username, password.clone()), (u2, p2));
        let (_, p3) = mint_ephemeral_turn_credentials("different", "user-1", now_ms);
        assert_ne!(p3, password);
    }

    #[test]
    fn peer_revocation_registry_round_trips() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        assert!(!is_business_peer_revoked(root, "peer-abc"));
        revoke_business_peer(root, "peer-abc", "admin-1", "stolen device")?;
        assert!(is_business_peer_revoked(root, "peer-abc"));
        assert!(!is_business_peer_revoked(root, "peer-xyz"));
        let listed = list_revoked_business_peers(root)?;
        assert_eq!(listed.len(), 1);
        assert_eq!(listed[0]["peer_id"], "peer-abc");
        assert_eq!(listed[0]["revoked_by"], "admin-1");
        clear_business_peer_revocation(root, "peer-abc")?;
        assert!(!is_business_peer_revoked(root, "peer-abc"));
        assert!(list_revoked_business_peers(root)?.is_empty());
        Ok(())
    }

    #[test]
    fn rxdb_table_names_cache_ignores_wal_and_shm_churn() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let path = temp.path().join(RXDB_STORE_FILE);
        let conn = Connection::open(&path)?;
        conn.execute(
            "CREATE TABLE ctox_business_os__business_chats__v1 (id TEXT PRIMARY KEY, data TEXT)",
            [],
        )?;

        let initial_stamp = rxdb_store_stamp(&path);
        fs::write(sqlite_sidecar_path(&path, "-wal"), b"first wal write")?;
        fs::write(sqlite_sidecar_path(&path, "-shm"), b"first shm write")?;
        assert_eq!(initial_stamp, rxdb_store_stamp(&path));

        let tables = rxdb_table_names_cached(&path, &conn)?;
        assert!(tables.contains("ctox_business_os__business_chats__v1"));

        fs::write(sqlite_sidecar_path(&path, "-wal"), b"second wal write")?;
        fs::write(sqlite_sidecar_path(&path, "-shm"), b"second shm write")?;
        assert_eq!(tables, rxdb_table_names_cached(&path, &conn)?);
        Ok(())
    }

    #[test]
    fn unauthenticated_public_surface_does_not_get_local_dev_admin() {
        let _env = EnvRestore::set(&[
            ("CTOX_AUTH_USERS", ""),
            ("CTOX_BUSINESS_PASSWORD", ""),
            ("CTOX_BUSINESS_OS_DESKTOP_ROLE", "admin"),
            ("CTOX_BUSINESS_OS_LOGIN_URL", ""),
            ("CTOX_BUSINESS_OS_REQUIRE_LOGIN", "0"),
            ("CTOX_BUSINESS_OS_SESSION_TOKEN", ""),
        ]);

        let public = session_for_request(None, None, false);
        assert!(!public.authenticated);
        assert!(public.auth_required);
        assert!(public.user.is_none());
        assert_eq!(
            public.reason.as_deref(),
            Some("ctox_session_token_not_configured")
        );

        let local = session_for_request(None, None, true);
        assert!(local.authenticated);
        assert_eq!(
            local.user.as_ref().map(|user| user.role.as_str()),
            Some("admin")
        );
    }

