    #[test]
    fn app_create_rxdb_command_accepts_type_alias_from_cli_dispatch() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let accepted = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_app_type_alias",
                "module": "creator",
                "type": "ctox.business_os.app.create",
                "record_id": "inventory",
                "payload": {
                    "title": "Build Inventory",
                    "instruction": "Build a Business OS inventory app.",
                    "module_id": "inventory",
                    "install_target": "runtime-installed-module",
                    "target": "app"
                },
                "client_context": {
                    "source": "business-os-app-creator-native-test",
                    "target": "app",
                    "capability_token": "SECRET_QUEUE_METADATA_TOKEN"
                }
            }),
        )?;

        assert_eq!(
            accepted.get("status").and_then(Value::as_str),
            Some("accepted")
        );
        let conn = open_store(root)?;
        let command_type: String = conn.query_row(
            "SELECT command_type FROM business_commands WHERE command_id = ?1",
            params!["cmd_app_type_alias"],
            |row| row.get(0),
        )?;
        assert_eq!(command_type, "ctox.business_os.app.create");
        let task_id = accepted
            .get("task_id")
            .and_then(Value::as_str)
            .context("expected queued task id")?;
        let task = channels::load_queue_task(root, task_id)?.context("expected queue task")?;
        assert_eq!(
            task.suggested_skill.as_deref(),
            Some(BUSINESS_OS_APP_MODULE_SKILL_NAME)
        );
        assert!(
            task.thread_key
                .starts_with("business-os/app-creator/inventory/"),
            "app create tasks must use an isolated app-creator thread, got {}",
            task.thread_key
        );
        assert!(task.prompt.contains("- type: ctox.business_os.app.create"));
        assert!(!task.prompt.contains("SECRET_QUEUE_METADATA_TOKEN"));
        assert!(!task.prompt.contains("capability_token"));
        let channel_conn = channels::open_channel_db(&crate::paths::core_db(root))?;
        let metadata_raw: String = channel_conn.query_row(
            "SELECT metadata_json FROM communication_messages WHERE message_key = ?1",
            params![task_id],
            |row| row.get(0),
        )?;
        assert!(!metadata_raw.contains("SECRET_QUEUE_METADATA_TOKEN"));
        assert!(!metadata_raw.contains("capability_token"));
        let metadata: Value = serde_json::from_str(&metadata_raw)?;
        assert_eq!(
            metadata
                .pointer("/client_context/source")
                .and_then(Value::as_str),
            Some("business-os-app-creator-native-test")
        );
        Ok(())
    }

