    #[test]
    fn app_validation_success_accepts_postlease_artifact_write() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let module_id = "inventory";
        seed_test_business_os_app_root(root)?;
        let accepted = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_app_postlease_write",
                "module": "creator",
                "type": "ctox.business_os.app.create",
                "record_id": module_id,
                "payload": {
                    "title": "Build Inventory",
                    "instruction": "Build a Business OS inventory app.",
                    "module_id": module_id,
                    "install_target": "runtime-installed-module",
                    "target": "app"
                },
                "client_context": {
                    "source": "business-os-app-creator-native-test",
                    "target": "app"
                }
            }),
        )?;
        let task_id = accepted
            .get("task_id")
            .and_then(Value::as_str)
            .context("expected queued task id")?
            .to_string();
        channels::lease_queue_task(root, &task_id, "ctox-service-test")?;
        thread::sleep(Duration::from_millis(1100));
        write_minimal_runtime_app_artifacts(root, module_id)?;

        let completed = complete_business_command_from_app_validation_success(
            root,
            &task_id,
            Some(module_id),
            "validated after app artifact write",
        )?;
        let completed = completed.context("expected app validation completion payload")?;
        assert_eq!(
            completed
                .pointer("/result/native_schema_refresh/status")
                .and_then(Value::as_str),
            Some("deferred_until_native_peer_start")
        );
        let task = channels::load_queue_task(root, &task_id)?
            .context("expected queue task after completion")?;
        assert_eq!(task.route_status, "handled");
        let conn = open_store(root)?;
        let status: String = conn.query_row(
            "SELECT status FROM business_commands WHERE command_id = ?1",
            params!["cmd_app_postlease_write"],
            |row| row.get(0),
        )?;
        assert_eq!(status, "completed");
        let catalog =
            load_rxdb_collection_record(root, "business_module_catalog", "module-catalog")?
                .context("expected module catalog projection")?;
        let module_present = catalog
            .get("modules")
            .and_then(Value::as_array)
            .is_some_and(|modules| {
                modules
                    .iter()
                    .any(|module| module.get("id").and_then(Value::as_str) == Some(module_id))
            });
        assert!(
            module_present,
            "validated app must be present in the RxDB module catalog"
        );
        let module = catalog
            .get("modules")
            .and_then(Value::as_array)
            .and_then(|modules| {
                modules
                    .iter()
                    .find(|module| module.get("id").and_then(Value::as_str) == Some(module_id))
            })
            .context("expected validated app in catalog")?;
        assert_eq!(
            module
                .pointer("/lifecycle/creator_user_id")
                .and_then(Value::as_str),
            Some("rxdb-command")
        );
        assert!(
            module
                .pointer("/lifecycle/responsible_user_ids")
                .and_then(Value::as_array)
                .is_some_and(|ids| ids.iter().any(|id| id.as_str() == Some("rxdb-command"))),
            "validated private app must be visible to its creating actor"
        );
        assert_eq!(
            module
                .pointer("/lifecycle/release_required_checks/source_snapshot")
                .and_then(Value::as_bool),
            Some(true)
        );
        let founder_count: i64 = conn.query_row(
            "SELECT COUNT(*)
             FROM business_module_acl
             WHERE module_id = ?1
               AND user_id = 'rxdb-command'
               AND role = 'founder'
               AND active = 1",
            params![module_id],
            |row| row.get(0),
        )?;
        assert_eq!(founder_count, 1);
        Ok(())
    }

