    #[test]
    fn app_validation_success_refuses_catalog_mismatched_module_manifest() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let module_id = "quality";
        seed_test_business_os_app_root(root)?;
        let accepted = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_app_catalog_mismatch",
                "module": "creator",
                "type": "ctox.business_os.app.create",
                "record_id": module_id,
                "payload": {
                    "title": "Build Quality",
                    "instruction": "Build a Business OS quality compliance app.",
                    "module_id": module_id,
                    "install_target": "runtime-installed-module",
                    "target": "app"
                },
                "client_context": {
                    "source": "business-os-app-creator-native-test",
                    "target": "app"
                }
            }),
        )?;
        let task_id = accepted
            .get("task_id")
            .and_then(Value::as_str)
            .context("expected queued task id")?
            .to_string();
        channels::lease_queue_task(root, &task_id, "ctox-service-test")?;
        thread::sleep(Duration::from_millis(1100));
        write_minimal_runtime_app_artifacts(root, module_id)?;
        let module_dir = root
            .join("runtime/business-os/installed-modules")
            .join(module_id);
        fs::write(
            module_dir.join("module.json"),
            serde_json::to_vec_pretty(&serde_json::json!({
                "id": "quality_shadow",
                "title": "Quality Shadow",
                "version": "0.1.0",
                "entry": format!("installed-modules/{module_id}/index.html"),
                "install_scope": "installed",
                "collections": ["business_commands", "quality_records"],
                "layout": {
                    "shell": "full-workspace",
                    "left": "Records",
                    "center": "Detail"
                }
            }))?,
        )?;

        let error = complete_business_command_from_app_validation_success(
            root,
            &task_id,
            Some(module_id),
            "validated with mismatched manifest id",
        )
        .expect_err("module catalog mismatch must not complete an app command");
        let report = format!("{error:#}");
        assert!(
            report
                .contains("module catalog projection does not contain validated module `quality`"),
            "unexpected error: {report}"
        );
        let task = channels::load_queue_task(root, &task_id)?
            .context("expected queue task after refused completion")?;
        assert_eq!(task.route_status, "leased");
        let conn = open_store(root)?;
        let status: String = conn.query_row(
            "SELECT status FROM business_commands WHERE command_id = ?1",
            params!["cmd_app_catalog_mismatch"],
            |row| row.get(0),
        )?;
        assert_eq!(status, "accepted");
        Ok(())
    }

    #[test]
    fn app_build_commands_enforce_policy_before_queueing() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        seed_business_user(root, "viewer", "user")?;
        seed_business_user(root, "app_owner", "founder")?;
        seed_business_user(root, "ops_admin", "admin")?;
        seed_module_founder_acl(root, "inventory", "app_owner")?;

        let team_modify = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_team_modify_app",
                "module": "creator",
                "type": "ctox.business_os.app.modify",
                "record_id": "inventory",
                "payload": {
                    "module_id": "inventory",
                    "instruction": "Change Inventory",
                    "target": "app"
                },
                "client_context": {
                    "actor": {
                        "id": "viewer",
                        "display_name": "Viewer",
                        "role": "admin"
                    }
                }
            }),
        )?;
        assert_eq!(team_modify.get("ok").and_then(Value::as_bool), Some(false));
        assert_eq!(
            team_modify.get("status").and_then(Value::as_str),
            Some("failed")
        );
        assert!(
            channels::list_queue_tasks(root, &[], 256)?.is_empty(),
            "denied app modify command must not create a queue task"
        );
        let conn = open_store(root)?;
        let denied =
            outbound_load_required(&conn, "business_commands", "cmd_team_modify_app", "command")?;
        assert_eq!(denied.get("status").and_then(Value::as_str), Some("failed"));
        assert_eq!(
            denied
                .pointer("/result/policy_decision/permission")
                .and_then(Value::as_str),
            Some("apps.modify")
        );
        assert_eq!(
            denied
                .pointer("/result/policy_decision/scope_type")
                .and_then(Value::as_str),
            Some("module")
        );
        assert_eq!(
            denied
                .pointer("/result/policy_decision/scope_id")
                .and_then(Value::as_str),
            Some("inventory")
        );
        assert_eq!(
            denied
                .pointer("/result/policy_decision/reason_code")
                .and_then(Value::as_str),
            Some("role_or_scope_denied")
        );
        assert!(
            denied
                .pointer("/result/policy_decision/display_reason")
                .and_then(Value::as_str)
                .unwrap_or_default()
                .contains("not allowed")
        );
        drop(conn);

        let founder_unassigned = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_founder_modify_unassigned_app",
                "module": "creator",
                "type": "ctox.business_os.app.modify",
                "record_id": "sales",
                "payload": {
                    "module_id": "sales",
                    "instruction": "Change Sales",
                    "target": "app"
                },
                "client_context": {
                    "actor": {
                        "id": "app_owner",
                        "display_name": "App Owner"
                    }
                }
            }),
        )?;
        assert_eq!(
            founder_unassigned.get("status").and_then(Value::as_str),
            Some("failed")
        );

        let founder_assigned = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_founder_modify_assigned_app",
                "module": "creator",
                "type": "ctox.business_os.app.modify",
                "record_id": "inventory",
                "payload": {
                    "module_id": "inventory",
                    "instruction": "Change Inventory",
                    "target": "app"
                },
                "client_context": {
                    "actor": {
                        "id": "app_owner",
                        "display_name": "App Owner"
                    }
                }
            }),
        )?;
        assert_eq!(
            founder_assigned.get("status").and_then(Value::as_str),
            Some("accepted")
        );
        let task_id = founder_assigned
            .get("task_id")
            .and_then(Value::as_str)
            .context("expected assigned founder app modify queue task")?;
        let task = channels::load_queue_task(root, task_id)?.context("expected queue task")?;
        assert!(task.prompt.contains("- module_id: inventory"));

        let team_create = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_team_create_app",
                "module": "creator",
                "type": "ctox.business_os.app.create",
                "record_id": "warehouse",
                "payload": {
                    "module_id": "warehouse",
                    "instruction": "Create Warehouse",
                    "target": "app"
                },
                "client_context": {
                    "actor": {
                        "id": "viewer",
                        "display_name": "Viewer"
                    }
                }
            }),
        )?;
        assert_eq!(
            team_create.get("status").and_then(Value::as_str),
            Some("failed")
        );
        let conn = open_store(root)?;
        let denied_create =
            outbound_load_required(&conn, "business_commands", "cmd_team_create_app", "command")?;
        assert_eq!(
            denied_create
                .pointer("/result/policy_decision/permission")
                .and_then(Value::as_str),
            Some("apps.install")
        );
        assert_eq!(
            denied_create
                .pointer("/result/policy_decision/scope_id")
                .and_then(Value::as_str),
            Some("warehouse")
        );
        drop(conn);

        let admin_create = accept_rxdb_business_command(
            root,
            serde_json::json!({
                "id": "cmd_admin_create_app",
                "module": "creator",
                "type": "ctox.business_os.app.create",
                "record_id": "warehouse",
                "payload": {
                    "module_id": "warehouse",
                    "instruction": "Create Warehouse",
                    "target": "app"
                },
                "client_context": {
                    "actor": {
                        "id": "ops_admin",
                        "display_name": "Ops Admin"
                    }
                }
            }),
        )?;
        assert_eq!(
            admin_create.get("status").and_then(Value::as_str),
            Some("accepted")
        );
        Ok(())
    }

    #[test]
    fn github_source_url_and_validation() {
        assert_eq!(
            github_archive_url("acme/widgets", "main"),
            "https://codeload.github.com/acme/widgets/zip/main"
        );
        assert_eq!(
            validate_github_repo(" acme/widgets/ ").unwrap(),
            "acme/widgets"
        );
        assert!(validate_github_repo("acme").is_err());
        assert!(validate_github_repo("acme/widgets/extra").is_err());
        assert!(validate_github_repo("../etc/passwd").is_err());
        assert!(validate_github_repo("acme/..").is_err());
        assert_eq!(sanitize_git_ref("").unwrap(), "HEAD");
        assert_eq!(sanitize_git_ref("v1.2.3").unwrap(), "v1.2.3");
        assert!(sanitize_git_ref("a b").is_err());
        assert!(sanitize_git_ref("a/../b").is_err());
        assert_eq!(source_relative_subpath("/modules/x/").unwrap(), "modules/x");
        assert!(source_relative_subpath("../x").is_err());
    }

    #[test]
    fn instance_visibility_base_then_install() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let _conn = open_store(root)?;
        let installed_app_root = resolve_business_os_installed_app_root(root);

        // An empty, brand-new instance provisions as the minimal base set.
        assert_eq!(
            business_os_provisioning_mode(root, &installed_app_root),
            "base"
        );

        let mut modules = vec![
            serde_json::json!({"id": "ctox", "lifecycle": {"runtime_installed": false}}),
            serde_json::json!({"id": "matching", "lifecycle": {"runtime_installed": false}}),
        ];
        augment_modules_with_instance_visibility(root, &installed_app_root, &mut modules);
        assert_eq!(modules[0]["instance_visible"], Value::Bool(true)); // core base set
        assert_eq!(modules[1]["instance_visible"], Value::Bool(false)); // non-core, not installed

        // Installing a catalog module as a tab makes it visible.
        business_os_set_module_visible(root, "matching", true)?;
        let mut after =
            vec![serde_json::json!({"id": "matching", "lifecycle": {"runtime_installed": false}})];
        augment_modules_with_instance_visibility(root, &installed_app_root, &mut after);
        assert_eq!(after[0]["instance_visible"], Value::Bool(true));
        Ok(())
    }

    #[test]
    fn instance_with_content_stays_legacy() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let conn = open_store(root)?;
        // A used instance (more than a bootstrap user) must keep every app.
        conn.execute(
            "INSERT INTO business_users
                (user_id, display_name, role, active, created_at_ms, updated_at_ms)
             VALUES ('a','A','admin',1,1,1), ('b','B','user',1,1,1)",
            [],
        )?;
        let installed_app_root = resolve_business_os_installed_app_root(root);
        assert_eq!(
            business_os_provisioning_mode(root, &installed_app_root),
            "legacy"
        );
        let mut modules =
            vec![serde_json::json!({"id": "matching", "lifecycle": {"runtime_installed": false}})];
        augment_modules_with_instance_visibility(root, &installed_app_root, &mut modules);
        assert_eq!(modules[0]["instance_visible"], Value::Bool(true));
        Ok(())
    }

    #[test]
    fn github_update_available_from_recorded_remote() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        let _conn = open_store(root)?;
        let app_root = temp.path().join("app");
        let version_states = serde_json::json!({
            "extapp": {
                "baseline_bundle_sha256": "INSTALLED_SHA",
                "current_bundle_sha256": "INSTALLED_SHA"
            }
        });
        let github_module = || {
            serde_json::json!({
                "id": "extapp",
                "version": "1.0.0",
                "app_source": { "kind": "github", "repo": "a/b" },
                "lifecycle": { "runtime_installed": true }
            })
        };

        // A newer upstream than the install baseline => update available.
        business_os_set_module_remote_sha(root, "extapp", "REMOTE_SHA")?;
        let mut modules = vec![github_module()];
        augment_modules_with_catalog_update_state(root, &app_root, &mut modules, &version_states);
        assert_eq!(
            modules[0]["lifecycle"]["update_available"],
            Value::Bool(true)
        );

        // Same upstream as installed => no update.
        business_os_set_module_remote_sha(root, "extapp", "INSTALLED_SHA")?;
        let mut modules = vec![github_module()];
        augment_modules_with_catalog_update_state(root, &app_root, &mut modules, &version_states);
        assert_eq!(
            modules[0]["lifecycle"]["update_available"],
            Value::Bool(false)
        );
        Ok(())
    }

