    #[test]
    fn rxdb_data_plane_status_reports_critical_collection_counts() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        fs::create_dir_all(root.join("runtime"))?;
        let sqlite_path = rxdb_store_path(root);
        let conn = Connection::open(sqlite_path)?;
        for collection in [
            "business_module_catalog",
            "ctox_runtime_settings",
            "desktop_files",
            "desktop_file_chunks",
        ] {
            conn.execute(
                &format!(
                    "CREATE TABLE ctox_business_os__{collection}__v0 (id TEXT PRIMARY KEY, data TEXT NOT NULL)"
                ),
                [],
            )?;
        }
        conn.execute(
            "CREATE TABLE ctox_business_os__business_commands__v1 (id TEXT PRIMARY KEY, data TEXT NOT NULL)",
            [],
        )?;
        conn.execute(
            "INSERT INTO ctox_business_os__business_commands__v1 (id, data) VALUES ('cmd-1', ?1)",
            [serde_json::json!({"updated_at_ms": 1200, "status": "accepted"}).to_string()],
        )?;
        conn.execute(
            "INSERT INTO ctox_business_os__business_module_catalog__v0 (id, data) VALUES ('module-catalog', ?1)",
            [serde_json::json!({"updated_at_ms": 1000, "modules": [{"id": "ctox"}]}).to_string()],
        )?;
        conn.execute(
            "INSERT INTO ctox_business_os__ctox_runtime_settings__v0 (id, data) VALUES ('runtime-settings', ?1)",
            [serde_json::json!({"updated_at_ms": 1100}).to_string()],
        )?;

        let status = rxdb_data_plane_status(root);
        assert_eq!(status.get("ok").and_then(Value::as_bool), Some(true));
        assert_eq!(
            status
                .pointer("/collections/business_module_catalog/row_count")
                .and_then(Value::as_i64),
            Some(1)
        );
        assert_eq!(
            status
                .pointer("/collections/ctox_runtime_settings/latest_updated_at_ms")
                .and_then(Value::as_i64),
            Some(1100)
        );
        assert_eq!(
            status.pointer("/collections/desktop_file_chunks/latest_updated_at_ms"),
            Some(&Value::Null)
        );
        assert_eq!(
            status.pointer("/collections/desktop_file_chunks/row_count"),
            Some(&Value::Null)
        );
        assert_eq!(
            status
                .pointer("/collections/desktop_files/ok")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            status
                .pointer("/collections/business_commands/table")
                .and_then(Value::as_str),
            Some("ctox_business_os__business_commands__v1")
        );
        Ok(())
    }

    #[test]
    fn rxdb_projection_writer_cache_reuses_table_metadata_for_batch() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        fs::create_dir_all(root.join("runtime"))?;
        let table = "ctox_business_os__writer_probe__v0";
        let sqlite_path = rxdb_store_path(root);
        let conn = Connection::open(sqlite_path)?;
        conn.execute(
            &format!(
                "CREATE TABLE {table} (
                    id TEXT PRIMARY KEY NOT NULL,
                    revision TEXT,
                    deleted INTEGER NOT NULL DEFAULT 0,
                    lastWriteTime REAL NOT NULL DEFAULT 0,
                    data TEXT NOT NULL
                )"
            ),
            [],
        )?;
        drop(conn);

        reset_rxdb_table_column_load_count(root, table);
        reset_rxdb_collection_writer_open_count(root, "writer_probe");
        let mut writers = RxdbProjectionWriterCache::new(root);
        for idx in 0..5 {
            writers.upsert(
                "writer_probe",
                &format!("probe-{idx}"),
                1_000 + idx,
                serde_json::json!({
                    "id": format!("probe-{idx}"),
                    "name": format!("Probe {idx}")
                }),
            )?;
        }

        assert_eq!(
            rxdb_table_column_load_count(root, table),
            1,
            "projection writer cache must not run PRAGMA table_info per upsert"
        );
        assert_eq!(
            rxdb_collection_writer_open_count(root, "writer_probe"),
            1,
            "projection writer cache must not reopen SQLite per upsert"
        );
        let conn = Connection::open(rxdb_store_path(root))?;
        let count: i64 = conn.query_row(&format!("SELECT COUNT(*) FROM {table}"), [], |row| {
            row.get(0)
        })?;
        assert_eq!(count, 5);
        let last_write_time: f64 = conn.query_row(
            &format!("SELECT lastWriteTime FROM {table} WHERE id = 'probe-4'"),
            [],
            |row| row.get(0),
        )?;
        assert_eq!(last_write_time, 1_004.0);
        Ok(())
    }

    #[test]
    fn rxdb_projection_writer_cache_reuses_writers_across_command_fanout() -> anyhow::Result<()> {
        let temp = tempdir()?;
        let root = temp.path();
        fs::create_dir_all(root.join("runtime"))?;
        let collections = [
            (
                "business_commands",
                "ctox_business_os__business_commands__v1",
            ),
            ("ctox_queue_tasks", "ctox_business_os__ctox_queue_tasks__v0"),
            ("business_chats", "ctox_business_os__business_chats__v0"),
            ("research_runs", "ctox_business_os__research_runs__v0"),
        ];
        let sqlite_path = rxdb_store_path(root);
        let conn = Connection::open(sqlite_path)?;
        for (_, table) in collections {
            conn.execute(
                &format!(
                    "CREATE TABLE {table} (
                        id TEXT PRIMARY KEY NOT NULL,
                        revision TEXT,
                        deleted INTEGER NOT NULL DEFAULT 0,
                        lastWriteTime REAL NOT NULL DEFAULT 0,
                        data TEXT NOT NULL
                    )"
                ),
                [],
            )?;
        }
        drop(conn);

        for (collection, table) in collections {
            reset_rxdb_table_column_load_count(root, table);
            reset_rxdb_collection_writer_open_count(root, collection);
        }
        let mut writers = RxdbProjectionWriterCache::new(root);
        for idx in 0..100 {
            for (collection, _) in collections {
                upsert_rxdb_collection_record_cached(
                    root,
                    Some(&mut writers),
                    collection,
                    &format!("{collection}-{idx}"),
                    2_000 + idx,
                    serde_json::json!({
                        "id": format!("{collection}-{idx}"),
                        "fanout_index": idx,
                        "collection": collection
                    }),
                )?;
            }
        }

        for (collection, table) in collections {
            assert_eq!(
                rxdb_table_column_load_count(root, table),
                1,
                "{collection} must not run PRAGMA table_info per fanout upsert"
            );
            assert_eq!(
                rxdb_collection_writer_open_count(root, collection),
                1,
                "{collection} must not reopen SQLite per fanout upsert"
            );
        }
        let conn = Connection::open(rxdb_store_path(root))?;
        for (_, table) in collections {
            let count: i64 =
                conn.query_row(&format!("SELECT COUNT(*) FROM {table}"), [], |row| {
                    row.get(0)
                })?;
            assert_eq!(count, 100);
        }
        Ok(())
    }

